def get_real_text_coverage() -> float:
    """Return fraction of 6236 verses with real Arabic text."""
    total = sum(VERSE_COUNTS.values())
    real = sum(1 for v in _ARABIC_TEXT.values() if v)
    return real / total


def load_quran_corpus() -> dict:
    """Load the complete Quran corpus.

    Returns a dict mapping (surah, verse) tuples to verse data dicts with keys:
        - surah: int (1-114)
        - verse: int (1-N)
        - text_ar: str (Arabic text or placeholder)
        - has_real_text: bool

    Real Arabic text is included for:
        - Al-Fatihah (1:1-7)
        - Al-Baqarah (2:1-5) and Ayat al-Kursi (2:255)
        - Al-Ikhlas (112:1-4)
        - Al-Falaq (113:1-5)
        - An-Nas (114:1-6)

    All other verses use placeholder text in the format "surah:verse".
    """
    corpus = {}
    for surah, count in VERSE_COUNTS.items():
        for verse in range(1, count + 1):
            key = (surah, verse)
            real_text = _ARABIC_TEXT.get(key)
            corpus[key] = {
                "surah": surah,
                "verse": verse,
                "text_ar": real_text if real_text else f"{surah}:{verse}",
                "has_real_text": real_text is not None,
            }
    return corpus
